/**
 * Tool-Usage Observer — Phase 1：observation 寫入層
 *
 * 把 tool 使用落盤成結構化 JSONL（observations.jsonl），供 Phase 2 的
 * instinct-evolve analyzer 萃取 skill。本檔是「唯一寫入收斂點」：負責
 * schema 組裝、脫敏、截斷、size cap、fail-silent，零業務邏輯外洩。
 *
 * 雙層訊號（兩條 Provider 路徑都收）：
 *  - Tier A（seq）：sessionManager 在 tool_call_update 寫，僅 ACP 路徑。
 *    只有 name+status+precedingTools，且 precedingTools 是「完成順序近似」
 *    （ACP 進程外並行跑 tool，update 到達序 ≠ 發起序）→ 標
 *    precedingToolsSemantics:"completion-order-approx"，避免 Phase 2 誤當發起序。
 *  - Tier B（rich）：tool-loop 在 executeToolCalls 內寫，僅 DirectProvider。
 *    含 args（脫敏）+output（截斷）+isError，precedingTools 為 loop-local 發起序
 *    → precedingToolsSemantics:"exec-order"。
 *
 * fail-silent：寫入失敗只 console.error，絕不向上拋（不得中斷 tool loop / session）。
 */
import { appendFileSync, existsSync, mkdirSync, statSync } from "node:fs";
import { dirname, join } from "node:path";
import { config } from "./config.js";

// ─── 常數 ────────────────────────────────────────────────────────────────

/** turn 邊界哨兵。resetTurn 時 push，Phase 2 analyzer 見此即切斷 combo（不跨 turn）。 */
export const TURN_MARKER = " TURN ";

/** precedingTools 滾動長度上限（含 turn marker，避免長駐 session 無界增長）。 */
const MAX_RECENT = 8;

/** observations.jsonl 體積上限；超過即安靜停寫（Phase 1 不滾動，Phase 2 補 rotate）。 */
const OBS_MAX_BYTES = 32 * 1024 * 1024;

/** 單筆 rich output 的 hard cap。observer 自帶，不借 tool-loop 的 maxToolResultChars（非 local 時為 undefined=不截斷）。 */
const OBS_MAX_OUTPUT_CHARS = 8 * 1024;

/** 脫敏：key 名命中即把值替為 [REDACTED]。 */
const SECRET_KEY_RE = /token|key|secret|password|authorization|auth/i;

/** observations.jsonl 預設路徑（測試可用 BRIDGE_OBSERVATIONS_PATH 覆蓋）。 */
export const OBSERVATIONS_PATH = join(config.memoryDir, "observations.jsonl");

// ─── 型別 ────────────────────────────────────────────────────────────────

export type PrecedingSemantics = "exec-order" | "completion-order-approx";

export interface Observation {
  ts: string;
  source: "seq" | "rich";
  name: string;
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
  precedingToolsSemantics: PrecedingSemantics;
  /** seq only */
  status?: "completed" | "failed";
  /** rich only — 經 redactArgs。 */
  args?: Record<string, unknown>;
  /** rich only — 經截斷。 */
  output?: string;
  /** rich only */
  isError?: boolean;
}

export interface SeqObservationInput {
  name: string;
  status: "completed" | "failed";
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
}

export interface RichObservationInput {
  name: string;
  args: Record<string, unknown>;
  output: string;
  isError: boolean;
  sessionId: string;
  chatId?: number;
  precedingTools: string[];
}

// ─── 內部工具 ─────────────────────────────────────────────────────────────

/** 寫入路徑：測試覆蓋優先，否則用 config.memoryDir 下的預設檔。 */
function observationsPath(): string {
  return process.env.BRIDGE_OBSERVATIONS_PATH || OBSERVATIONS_PATH;
}

/** redactArgs 遞迴深度上限（防 stack overflow / 病態巢狀）。 */
const MAX_REDACT_DEPTH = 4;

/**
 * shell command 內嵌 secret 的 best-effort 清除（不合約化、不宣稱無洩漏）。
 * 只清「明確的憑證形態」（Bearer / key=token=secret=password=），不碰一般旗標——
 * R-1：原本的 `-p\S+` 會誤殺 `mkdir -p /home`、`docker run -p 8080`、`grep -print` 等
 * 高頻非密碼旗標，污染 Phase 2 corpus，得不償失（mysql/pg 的緊貼式 -ppwd 屬已宣告
 * 「擋不住所有內嵌 secret」的誠實邊界，不為了它毀損正常指令）。
 */
function scrubSecretsInText(s: string): string {
  return s
    .replace(/Bearer\s+\S+/gi, "Bearer [REDACTED]")
    .replace(/\b(api[_-]?key|key|token|secret|password)\s*=\s*\S+/gi, "$1=[REDACTED]");
}

/** 單一值脫敏：key 名命中即整值替換；command 字串跑 scrub；object/array 在深度內遞迴。 */
function redactValue(key: string | undefined, v: unknown, depth: number): unknown {
  // key 名命中優先於一切（含巢狀內層）——R-3：{env:{API_KEY}} 的內層 key 也要脫。
  if (key && SECRET_KEY_RE.test(key)) return "[REDACTED]";
  if (key === "command" && typeof v === "string") return scrubSecretsInText(v);
  if (depth >= MAX_REDACT_DEPTH) return v; // 深度上限：停止下探，原值保留（不再 mutate）
  if (Array.isArray(v)) return v.map((item) => redactValue(undefined, item, depth + 1));
  if (v && typeof v === "object") return redactObject(v as Record<string, unknown>, depth + 1);
  return v;
}

function redactObject(obj: Record<string, unknown>, depth: number): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k] = redactValue(k, v, depth);
  }
  return out;
}

/**
 * 脫敏 args（best-effort，export 供測試）。深度受限遞迴：
 * - 任一層 key 名命中 SECRET_KEY_RE → 值替為 [REDACTED]（含巢狀 env/headers 內層）。
 * - command 字串值（shell tool 最高頻）→ 額外跑 value-level scrub。
 * - 非 mutating：回傳新物件，原 args 不變。
 * ⚠️ 已知限制（不合約化）：擋不住「值是 secret 但 key 名無關鍵字」者
 *   （如 command 內 `psql user:pass@host`、深度超過上限的巢狀）。Phase 2 讀取端可再過濾。
 */
export function redactArgs(args: Record<string, unknown>): Record<string, unknown> {
  return redactObject(args, 0);
}

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max) + `\n...[truncated ${s.length - max} chars]` : s;
}

/**
 * 唯一落盤點。收 build thunk 而非成品 → 整段 try/catch 真正涵蓋
 * 「schema 組裝 + 脫敏（redactArgs）+ 截斷（truncate）+ JSON.stringify + 同步寫入」
 * 的所有拋錯（R-4：原本 redact/truncate 在 try 外，註解過度宣稱）。fail-silent。
 * 沿用 event-log.ts 的 mkdirSync+appendFileSync 範式。
 */
function appendObservation(build: () => Observation): void {
  try {
    const obs = build();
    const target = observationsPath();
    // size cap：超過上限安靜停寫（不滾動、不刪除）
    if (existsSync(target) && statSync(target).size > OBS_MAX_BYTES) return;
    const dir = dirname(target);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    appendFileSync(target, JSON.stringify(obs) + "\n", "utf-8");
  } catch (err) {
    // observation 是旁路訊號，組裝/脫敏/寫入任一失敗都絕不影響主流程
    console.error("[tool-observer] failed to write observation:", err);
  }
}

// ─── 公開 API ─────────────────────────────────────────────────────────────

/** Tier A（ACP 路徑序列訊號）。fire-and-forget。 */
export function recordSeqObservation(input: SeqObservationInput): void {
  appendObservation(() => ({
    ts: new Date().toISOString(),
    source: "seq",
    name: input.name,
    status: input.status,
    sessionId: input.sessionId,
    chatId: input.chatId,
    precedingTools: input.precedingTools,
    precedingToolsSemantics: "completion-order-approx",
  }));
}

/** Tier B（DirectProvider rich 訊號）。fire-and-forget。 */
export function recordRichObservation(input: RichObservationInput): void {
  appendObservation(() => ({
    ts: new Date().toISOString(),
    source: "rich",
    name: input.name,
    sessionId: input.sessionId,
    chatId: input.chatId,
    precedingTools: input.precedingTools,
    precedingToolsSemantics: "exec-order",
    args: redactArgs(input.args),
    output: truncate(input.output, OBS_MAX_OUTPUT_CHARS),
    isError: input.isError,
  }));
}

/**
 * 把工具名（或 turn marker）push 進 rolling 序列並維持上限。
 * 兩條路徑共用此 helper 保證 cap 一致（避免無界增長）。
 */
export function appendToolName(recent: string[], name: string, max = MAX_RECENT): string[] {
  recent.push(name);
  const overflow = recent.length - max;
  if (overflow > 0) recent.splice(0, overflow);
  return recent;
}

/**
 * Event Log — 狀態轉移持久化記錄
 * 
 * 可查、可審計、可回放。30 天滾動清理。
 */

import { appendFileSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
import { dirname, join } from "path";
import { config } from "./config.js";

// ─── Types ─────────────────────────────────────────────────────────────────

export type EventType =
  | "session_start"
  | "session_end"
  | "goal_start"
  | "goal_step"
  | "goal_done"
  | "goal_cancel"
  | "specialist_spawn"
  | "specialist_done"
  | "reaction_feedback"
  | "scheduler_fire"
  | "tool_call"
  | "orphan_flush"
  | "error";

export interface StateEvent {
  ts: string;
  type: EventType;
  chatId?: number;
  userId?: number;
  payload: Record<string, unknown>;
}

// ─── Config ────────────────────────────────────────────────────────────────

const EVENT_LOG_PATH = join(config.memoryDir, "events.jsonl");
const RETENTION_DAYS = 30;

// ─── Core Functions ────────────────────────────────────────────────────────

/**
 * 寫入一筆 event
 */
export function logEvent(
  type: EventType,
  payload: Record<string, unknown> = {},
  opts: { chatId?: number; userId?: number } = {}
): void {
  const event: StateEvent = {
    ts: new Date().toISOString(),
    type,
    ...opts,
    payload,
  };

  try {
    // 確保目錄存在
    const dir = dirname(EVENT_LOG_PATH);
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }

    appendFileSync(EVENT_LOG_PATH, JSON.stringify(event) + "\n", "utf-8");
  } catch (err) {
    // Event log 失敗不應該影響主流程
    console.error("[event-log] Failed to write event:", err);
  }
}

/**
 * 讀取最近 n 筆 events
 */
export function getRecentEvents(n: number = 50): StateEvent[] {
  if (!existsSync(EVENT_LOG_PATH)) return [];

  try {
    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
    const lines = content.trim().split("\n").filter(Boolean);
    const events = lines
      .slice(-n)
      .map((line) => {
        try {
          return JSON.parse(line) as StateEvent;
        } catch {
          return null;
        }
      })
      .filter((e): e is StateEvent => e !== null);

    return events;
  } catch {
    return [];
  }
}

/**
 * 讀取特定類型的 events
 */
export function getEventsByType(type: EventType, n: number = 50): StateEvent[] {
  return getRecentEvents(n * 3).filter((e) => e.type === type).slice(-n);
}

/**
 * 讀取特定 chat 的 events
 */
export function getEventsByChat(chatId: number, n: number = 50): StateEvent[] {
  return getRecentEvents(n * 3).filter((e) => e.chatId === chatId).slice(-n);
}

/**
 * 滾動清理：刪除超過 RETENTION_DAYS 的 events
 * 
 * 建議在 /dream 時呼叫
 */
export function rotateEventLog(): { deleted: number; kept: number } {
  if (!existsSync(EVENT_LOG_PATH)) {
    return { deleted: 0, kept: 0 };
  }

  try {
    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
    const lines = content.trim().split("\n").filter(Boolean);

    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - RETENTION_DAYS);
    const cutoffStr = cutoff.toISOString();

    const kept: string[] = [];
    let deleted = 0;

    for (const line of lines) {
      try {
        const event = JSON.parse(line) as StateEvent;
        if (event.ts >= cutoffStr) {
          kept.push(line);
        } else {
          deleted++;
        }
      } catch {
        // 無法解析的行直接丟棄
        deleted++;
      }
    }

    writeFileSync(EVENT_LOG_PATH, kept.join("\n") + (kept.length ? "\n" : ""), "utf-8");

    return { deleted, kept: kept.length };
  } catch (err) {
    console.error("[event-log] Failed to rotate:", err);
    return { deleted: 0, kept: 0 };
  }
}

/**
 * 統計過去 days 天的 tool_call 使用次數，依工具名稱聚合。
 *
 * 回傳依使用次數由多到少排序的陣列；total 為總呼叫數、failed 為失敗數。
 */
export function getToolUsageStats(days: number = 7): {
  byTool: Array<{ name: string; total: number; failed: number }>;
  total: number;
  failed: number;
} {
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - days);
  const cutoffStr = cutoff.toISOString();

  const counts = new Map<string, { total: number; failed: number }>();
  let total = 0;
  let failed = 0;

  for (const e of getRecentEvents(10000)) {
    if (e.type !== "tool_call" || e.ts < cutoffStr) continue;
    const name = (e.payload?.name as string) ?? "tool";
    const isFail = e.payload?.status === "failed";
    const cur = counts.get(name) ?? { total: 0, failed: 0 };
    cur.total++;
    if (isFail) cur.failed++;
    counts.set(name, cur);
    total++;
    if (isFail) failed++;
  }

  const byTool = [...counts.entries()]
    .map(([name, v]) => ({ name, total: v.total, failed: v.failed }))
    .sort((a, b) => b.total - a.total);

  return { byTool, total, failed };
}

/**
 * 取得 event log 統計
 */
export function getEventLogStats(): {
  totalEvents: number;
  oldestEvent?: string;
  newestEvent?: string;
  byType: Record<string, number>;
} {
  const events = getRecentEvents(10000); // 讀取全部（最多 10000）

  if (events.length === 0) {
    return { totalEvents: 0, byType: {} };
  }

  const byType: Record<string, number> = {};
  for (const e of events) {
    byType[e.type] = (byType[e.type] || 0) + 1;
  }

  return {
    totalEvents: events.length,
    oldestEvent: events[0]?.ts,
    newestEvent: events[events.length - 1]?.ts,
    byType,
  };
}

/**
 * hit-log.ts — Track usage of facts/wiki/skills via append-only JSONL.
 * Provides stats for factlint "zero-hit" reporting and grouped evaluation.
 */
import { appendFile, readFile } from "node:fs/promises";
import { readFileSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";

const LOG_FILE = path.join(config.memoryDir, "hit-log.jsonl");

export interface HitEntry {
  ts: string;
  type: "fact" | "wiki" | "skill" | "index";
  key: string;
  source: string;
}

/** Append a hit entry. Fire-and-forget (never throws). */
export function logHit(type: HitEntry["type"], key: string, source: string): void {
  const entry: HitEntry = { ts: new Date().toISOString(), type, key, source };
  appendFile(LOG_FILE, JSON.stringify(entry) + "\n").catch(() => {});
}

/** Read hit log and return stats for the last N days. */
export async function getHitStats(days = 30): Promise<Map<string, number>> {
  const cutoff = Date.now() - days * 86_400_000;
  const stats = new Map<string, number>();
  let raw: string;
  try {
    raw = await readFile(LOG_FILE, "utf8");
  } catch {
    return stats;
  }
  for (const line of raw.split("\n")) {
    if (!line.trim()) continue;
    try {
      const e: HitEntry = JSON.parse(line);
      if (new Date(e.ts).getTime() < cutoff) continue;
      const k = `${e.type}:${e.key}`;
      stats.set(k, (stats.get(k) ?? 0) + 1);
    } catch { /* skip malformed */ }
  }
  return stats;
}

// ─── Repo Health (Compression Metric) ────────────────────────────────────────

const ACTIONABLE_RE = /因為|避免|不要|不可|遇到.*要|必須|禁止|改用|換成|確保|注意/;

export interface RepoHealth {
  total: number;
  actionable: number;
  ratio: number;
}

/** Compute repo health: ratio of total facts to actionable (guidance-bearing) facts. */
export function computeRepoHealth(shards: Array<{ file: string }>): RepoHealth {
  let total = 0, actionable = 0;
  for (const s of shards) {
    let content: string;
    try { content = readFileSync(s.file, "utf8"); } catch { continue; }
    for (const line of content.split(/\r?\n/)) {
      if (!line.trim() || !line.startsWith("-")) continue;
      total++;
      if (ACTIONABLE_RE.test(line)) actionable++;
    }
  }
  return { total, actionable, ratio: actionable > 0 ? total / actionable : total };
}

/**
 * Wiki Retrieval — semantically match user messages to wiki pages and
 * inject their content into the prompt, saving the agent a tool call.
 *
 * At init: parses wiki/index.md for slug→summary pairs, embeds each summary.
 * Per turn: embeds user message, finds top matching page(s), reads and injects content.
 */

import { readFileSync, existsSync } from "node:fs";
import path from "node:path";
import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";
import { config } from "./config.js";

// ─── Config ──────────────────────────────────────────────────────────────────

const WIKI_THRESHOLD = 0.65;
const WIKI_TOP_K = 2;
const MIN_MSG_LENGTH = 12;
/** Max chars to inject per wiki page (avoid blowing up context). */
const MAX_PAGE_CHARS = 3000;
/** Pages longer than this get section-index only (agent reads on demand).
 *  Set to 0 so ALL pages only inject section index — saves context budget. */
const LONG_PAGE_THRESHOLD = 0;

// ─── State ───────────────────────────────────────────────────────────────────

interface WikiEntry {
  slug: string;
  summary: string;
  vector: Float32Array;
}

let wikiEntries: WikiEntry[] = [];
let initialized = false;

// ─── Public API ──────────────────────────────────────────────────────────────

export async function initWikiRetrieval(): Promise<void> {
  if (!isEmbedRouterReady()) return;
  const indexPath = path.join(config.memoryDir, "wiki", "index.md");
  if (!existsSync(indexPath)) return;

  const entries = parseWikiIndex(indexPath);
  if (entries.length === 0) return;

  wikiEntries = [];
  for (const { slug, summary } of entries) {
    const repr = `${slug}: ${summary}`;
    const vec = await embedText(repr);
    if (vec) wikiEntries.push({ slug, summary, vector: vec });
  }
  initialized = true;
  console.log(`[wiki-retrieval] ready: ${wikiEntries.length} page vectors`);
}

export function isWikiRetrievalReady(): boolean {
  return initialized && wikiEntries.length > 0;
}

export interface WikiHit {

#!/usr/bin/env node
// Redirect all console output to stderr BEFORE any imports —
// MCP stdio transport requires stdout to be pure JSON-RPC.
console.log = console.error;
console.info = console.error;
console.warn = console.error;
console.debug = console.error;

// MCP server for long-term memory. Runs as a child of the ACP agent
// (spawned via ~/.kiro/agents/main.json mcpServers, or
// ~/.codex/config.toml [mcp_servers.memory] for Codex CLI standalone).
// Exposes remember / list_facts / forget / apply_topics / propose_topics.
//
// The active user id is taken from one of these, in priority order:
//   1. env TG_ACTIVE_USER_ID  — injected by telegram-kiro bridge
//   2. env MEMORY_USER_ID     — static config for standalone agents
//   3. file <MEMORY_DIR>/.user-id  — single-line plain text
//
// MEMORY_DIR env overrides the facts directory (defaults to
// F:\AI\AIMemory on Kiro, set to F:\AI_Codex\AIMemory on Codex box).
import { mkdir, readFile, appendFile } from "node:fs/promises";
import { readFileSync } from "node:fs";
import path from "node:path";
import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { keywordsForTopic, classifyFact, classifyFactAsync } from "./topic-rules.js";
import {
  appendFactShardOnly,
  readTopicFacts,
  formatFactLine,
  forgetMatch,
  forgetCommit,
  readAllFactsForReview,
  applyTopics,
  computeTopicsToken,
  normaliseProposedTopics,
  resolveMaxTopics,
} from "./facts-store.js";
import { factExists, insertFact, deleteFact } from "./memory-db.js";
import { ingestPrepare, ingestSave, listIndexes, queryIndex, findStaleIndexes, ingestUpdate, buildCrossRefs } from "./page-index.js";

const MEMORY_DIR = path.resolve(
  process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
    ? process.env.MEMORY_DIR
    : "F:\\AI\\AIMemory"
);

function activeUserId(): number {
  // Primary: TG_ACTIVE_USER_ID — set automatically by the telegram-kiro
  // bridge when it spawns the agent. Accept the shorter alias
  // MEMORY_USER_ID for standalone use (e.g. Codex CLI where the bridge
  // doesn't inject env, and the user statically configures the MCP
  // server via ~/.codex/config.toml [mcp_servers.memory.env]).
  // Finally, fall back to reading <MEMORY_DIR>/.user-id so the user can
  // drop a single-line file there instead of editing TOML.
  const envRaw =
    (process.env.TG_ACTIVE_USER_ID ?? "").trim() ||
    (process.env.MEMORY_USER_ID ?? "").trim();
  if (envRaw) {
    const n = Number(envRaw);
    if (Number.isFinite(n) && n > 0) return n;
  }
  try {
    const filePath = path.join(MEMORY_DIR, ".user-id");
    const raw = readFileSync(filePath, "utf8").trim();
    const n = Number(raw);
    if (Number.isFinite(n) && n > 0) return n;
  } catch {
    // ignore — fall through to error
  }
  throw new Error(
    "memory MCP: active user id not configured. Set one of:\n" +
      "  - env TG_ACTIVE_USER_ID (how the telegram-kiro bridge normally injects it), or\n" +
      "  - env MEMORY_USER_ID (set in ~/.codex/config.toml [mcp_servers.memory.env] for standalone Codex use), or\n" +
      `  - a plain-text file ${path.join(MEMORY_DIR, ".user-id")} containing just the Telegram user id.`
  );

async function remember(text: string, topic?: string): Promise<string> {
  const line = text.trim();
  if (!line) throw new Error("text is empty");
  const userId = activeUserId();
  await mkdir(MEMORY_DIR, { recursive: true });

  // Dedup check: precise content hash (SQLite) then Jaccard fallback.
