/**
 * Wiki Freshness Checker
 * 
 * 檢查專案內 wiki 文件是否需要重產。
 * 比較 .codegraph/db.json 的 mtime 和 .codegraph/wiki/ 內文件的 mtime。
 */

import { existsSync, statSync, readdirSync } from "fs";
import { join } from "path";

export interface FreshnessResult {
  needsRegen: boolean;
  dbMtime: Date | null;
  wikiMtime: Date | null;
  staleFiles: string[];
}

/**
 * 檢查專案的 wiki 是否需要重產
 * 
 * @param projectPath - 專案路徑
 * @returns FreshnessResult
 */
export function checkWikiFreshness(projectPath: string): FreshnessResult {
  const dbPath = join(projectPath, ".codegraph", "db.json");
  const wikiDir = join(projectPath, ".codegraph", "wiki");

  const result: FreshnessResult = {
    needsRegen: false,
    dbMtime: null,
    wikiMtime: null,
    staleFiles: [],
  };

  // 檢查 db.json 是否存在
  if (!existsSync(dbPath)) {
    return result;
  }

  // 取得 db.json 的 mtime
  const dbStat = statSync(dbPath);
  result.dbMtime = dbStat.mtime;

  // 檢查 wiki 目錄是否存在
  if (!existsSync(wikiDir)) {
    result.needsRegen = true;
    return result;
  }

  // 取得 wiki 目錄內所有 .md 檔案
  const wikiFiles = readdirSync(wikiDir).filter((f) => f.endsWith(".md"));

  if (wikiFiles.length === 0) {
    result.needsRegen = true;
    return result;
  }

  // 找出最舊的 wiki 檔案 mtime
  let oldestMtime: Date | null = null;

  for (const file of wikiFiles) {
    const filePath = join(wikiDir, file);
    const fileStat = statSync(filePath);

    if (!oldestMtime || fileStat.mtime < oldestMtime) {
      oldestMtime = fileStat.mtime;
    }

    // 如果 wiki 檔案比 db.json 舊，標記為 stale
    if (fileStat.mtime < dbStat.mtime) {
      result.staleFiles.push(file);
    }
  }

  result.wikiMtime = oldestMtime;
  result.needsRegen = result.staleFiles.length > 0;

  return result;
}

/**
 * 格式化 freshness 結果為人類可讀的訊息
 */
export function formatFreshnessMessage(result: FreshnessResult): string {
  if (!result.dbMtime) {
    return "No codegraph index found.";
  }

  if (!result.needsRegen) {
    return "Wiki is up to date.";
  }

  const lines = [
    "⚠️ Wiki needs regeneration:",
    `  - Index updated: ${result.dbMtime.toISOString()}`,
  ];

  if (result.wikiMtime) {
    lines.push(`  - Wiki oldest: ${result.wikiMtime.toISOString()}`);
  }

  if (result.staleFiles.length > 0) {
    lines.push(`  - Stale files: ${result.staleFiles.join(", ")}`);
  }

  return lines.join("\n");
}

const WIKISYNC_PROMPT =
  `請執行 wiki sync（依 ms-wiki-knowledge-base skill 的 wikisync 邏輯）：\n` +
  `0. 若 ${MEMORY_DIR}/wiki/ 目錄不存在，先建立 wiki/、wiki/concepts/、wiki/references/、wiki/lessons/、wiki/queries/ 並寫一份空 index.md（參考 SCHEMA.md 格式）。\n` +
  `1. 讀 ${MEMORY_DIR}/wiki/index.md 取得現有 wiki 頁面列表。\n` +
  `2. 呼叫 list_facts({ query: '', tail: 0 }) 或讀 topics.json 取得所有 topic 名稱。\n` +
  `3. 對每個 topic shard（≥5 facts 且 index.md 中無對應 wiki page）：\n` +
  `   - 呼叫 list_facts({ query: '<topic>' }) 讀 shard 內容\n` +
  `   - 產出一頁 ${MEMORY_DIR}/wiki/concepts/<topic>.md（結構化段落，不是 flat list）\n` +
  `   - 遵循 SCHEMA.md 的 frontmatter 格式、至少 1 個 [[wikilink]]、≤200 行\n` +
  `   - frontmatter sources 欄位記錄來源 fact IDs（格式：sources: [f_xxxxxx, f_yyyyyy, ...]），從 shard 行首 [f_xxxxxx] 提取\n` +
  `   - 若產出 type=lesson 頁面，frontmatter 加 why 欄位：從 shard facts 中找含「因為」「because」的句子，摘要成一句根因\n` +
  `4. 對已有 wiki page 但 shard 有明顯新內容的：更新頁面 + bump updated 日期 + 追加新 fact IDs 到 sources。\n` +
  `5. 每次新增/更新頁面後同步更新 index.md（加一行 wikilink + 摘要、更新 Total pages）。\n` +
  `6. 完成後回報：新增了哪些頁面、更新了哪些、跳過了哪些（含原因）。\n` +
  `用繁體中文撰寫所有 wiki 頁面。一次最多處理 5 個 topic，避免 context 爆炸。\n` +
  `回覆末尾加上：<<SKILL_USED:ms-wiki-knowledge-base|wikisync 步驟>>`;

export async function handleWikiSync(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }
  await runPrompt(ctx, session, WIKISYNC_PROMPT, { kind: "meta" });
}


// ─── /factlint ──────────────────────────────────────────────────────────────

const FACTLINT_PROMPT =
  "⛔ CRITICAL SAFETY RULE: NEVER directly read/write/filter facts-*.md via shell commands " +
  "(node -e, sed, powershell, cat, echo). Windows CRLF will break line matching and destroy data. " +
  "ALWAYS use the MCP `forget()` tool for deletion — it handles CRLF correctly.\n\n" +
