/**
 * ingest-ripple.ts — 漣漪式 Wiki 更新
 *
 * 當新 fact 寫入（remember）時，檢查是否有相關 wiki page 需要更新。
 * 設計原則：
 * - fire-and-forget，不阻塞 remember 主路徑
 * - 不直接改 wiki 頁面（那是 agent 的工作），只產出「待更新」標記
 * - 標記累積到門檻後，由 /dream 或 /wikisync 一次性處理
 *
 * 機制：
 * 1. 新 fact 寫入 → 取出 topic → 找到對應 wiki page
 * 2. 比對 wiki page 的 sources frontmatter → 算出「新增 facts 數」
 * 3. 新增 facts ≥ RIPPLE_THRESHOLD → 追加到 wiki-ripple.jsonl
 * 4. /dream 的 wikisync 步驟可讀取 ripple log 決定優先更新哪些頁面
 */

import { readFileSync, existsSync, appendFileSync, writeFileSync, mkdirSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";

// ─── 常數 ─────────────────────────────────────────────────────────────────

/** 累積多少新 fact 才標記為需更新 */
const RIPPLE_THRESHOLD = 3;

/** ripple log 最大筆數（防無界增長） */
const MAX_RIPPLE_ENTRIES = 200;

/** wiki index 路徑 */
const WIKI_INDEX_PATH = path.join(config.memoryDir, "wiki", "index.md");

/** ripple log 路徑 */
const RIPPLE_LOG_PATH = path.join(config.memoryDir, "wiki", "wiki-ripple.jsonl");

// ─── 型別 ─────────────────────────────────────────────────────────────────

export interface RippleEntry {
  /** ISO timestamp */
  ts: string;
  /** 觸發此 ripple 的 topic */
  topic: string;
  /** 對應的 wiki slug（如果有） */
  wikiSlug: string | null;
  /** wiki page 的 type（concepts / lessons / references） */
  wikiType: string | null;
  /** 觸發的 fact 文字（截斷） */
  factPreview: string;
  /** 該 page 目前累積的未同步 fact 數 */
  pendingCount: number;
  /** 是否達到更新門檻 */
  thresholdReached: boolean;
}

export interface RippleStatus {
  /** 需要更新的 wiki page（已達門檻） */
  pagesNeedingUpdate: Array<{
    slug: string;
    type: string;
    topic: string;
    pendingCount: number;
    lastRipple: string;
  }>;
  /** 尚未達門檻的 page */
  pagesWatching: Array<{
    slug: string;
    type: string;
    topic: string;
    pendingCount: number;
  }>;
}

// ─── 內部工具 ─────────────────────────────────────────────────────────────

/** 解析 wiki/index.md，取得 slug → topic 映射 */
function parseWikiIndex(): Map<string, { slug: string; type: string }> {
  const map = new Map<string, { slug: string; type: string }>();
  if (!existsSync(WIKI_INDEX_PATH)) return map;

  try {
    const content = readFileSync(WIKI_INDEX_PATH, "utf8");
    // 格式：- [[slug]] — 描述
    const re = /^-\s*\[\[([^\]]+)\]\]\s*—\s*(.+)$/gm;
    let m: RegExpExecArray | null;
    let currentType = "concepts";

    for (const line of content.split(/\r?\n/)) {
      // 偵測 section 標題
      if (/^##\s*Pages/i.test(line)) currentType = "concepts";
      else if (/^##\s*Lessons/i.test(line)) currentType = "lessons";
      else if (/^##\s*References/i.test(line)) currentType = "references";
      else if (/^##\s*Tasks/i.test(line)) currentType = "tasks";
      else if (/^##\s*Queries/i.test(line)) currentType = "queries";

      re.lastIndex = 0;
      m = re.exec(line);
      if (m) {
        const slug = m[1];
        // slug 通常就是 topic 名（kebab-case）
        map.set(slug, { slug, type: currentType });
      }
    }
  } catch { /* 讀取失敗，回傳空 map */ }
  return map;
}

/** 讀取 wiki page 的 sources frontmatter（fact IDs 列表） */
function getPageSources(slug: string, type: string): Set<string> {
  const sources = new Set<string>();
  const pagePath = path.join(config.memoryDir, "wiki", type, `${slug}.md`);
  if (!existsSync(pagePath)) return sources;

  try {
    const content = readFileSync(pagePath, "utf8");
    // frontmatter: sources: [f_xxxxxx, f_yyyyyy, ...]
    const match = content.match(/^sources:\s*\[([^\]]*)\]/m);
    if (match) {
      const ids = match[1].split(",").map((s) => s.trim()).filter(Boolean);
      for (const id of ids) sources.add(id);
    }
  } catch { /* 讀取失敗 */ }
  return sources;
}

/** 讀取 topic shard 的 fact IDs */
function getShardFactIds(topic: string): string[] {
  const userId = getActiveUserId();
  if (!userId) return [];

  // topic → filename：kebab-case 對應
  const shardDir = path.join(config.memoryDir, `facts_Topic`, String(userId));
  if (!existsSync(shardDir)) return [];

  // 找到對應 shard 檔案
  const candidates = [
    path.join(shardDir, `${topic}.md`),
    path.join(shardDir, `${topic.replace(/-/g, "_")}.md`),
  ];

  for (const filePath of candidates) {
    if (!existsSync(filePath)) continue;
    try {
      const content = readFileSync(filePath, "utf8");
      const ids: string[] = [];
      for (const line of content.split(/\r?\n/)) {
        const m = line.match(/\[f_([0-9a-f]{6})\]/);
        if (m) ids.push(`f_${m[1]}`);
      }
      return ids;
    } catch { /* 忽略 */ }
  }
  return [];
}

function getActiveUserId(): number | null {
  const raw = (process.env.TG_ACTIVE_USER_ID ?? "").trim() ||
    (process.env.MEMORY_USER_ID ?? "").trim();
  if (raw) {
    const n = Number(raw);
    if (Number.isFinite(n) && n > 0) return n;
  }
  try {
    const filePath = path.join(config.memoryDir, ".user-id");
    const content = readFileSync(filePath, "utf8").trim();
    const n = Number(content);
    if (Number.isFinite(n) && n > 0) return n;
  } catch { /* 忽略 */ }
  return null;
}

// ─── 公開 API ─────────────────────────────────────────────────────────────

/**
 * 新 fact 寫入時呼叫。fire-and-forget，不拋錯。
 * @param topic - 該 fact 被分類到的 topic
 * @param factText - fact 原文（用於 preview）
 * @param factId - fact ID（如 f_abc123）
 */
export function onFactIngested(topic: string, factText: string, factId?: string): void {
  try {
    const wikiIndex = parseWikiIndex();

    // 找到對應的 wiki page（topic slug = wiki slug）
    const wikiEntry = wikiIndex.get(topic);
    const wikiSlug = wikiEntry?.slug ?? null;
    const wikiType = wikiEntry?.type ?? null;

    // 計算 pending count
    let pendingCount = 1;
    if (wikiSlug && wikiType) {
      const pageSources = getPageSources(wikiSlug, wikiType);
      const shardIds = getShardFactIds(topic);
      // 未被 wiki page 追蹤的 fact 數
      pendingCount = shardIds.filter((id) => !pageSources.has(id)).length;
    }

    const entry: RippleEntry = {
      ts: new Date().toISOString(),
      topic,
      wikiSlug,
      wikiType,
      factPreview: factText.slice(0, 100),
      pendingCount,
      thresholdReached: pendingCount >= RIPPLE_THRESHOLD,
    };

    // 寫入 ripple log
    const dir = path.dirname(RIPPLE_LOG_PATH);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    appendFileSync(RIPPLE_LOG_PATH, JSON.stringify(entry) + "\n", "utf8");

    // 體積控制：超過上限時截斷
    trimRippleLog();
  } catch (err) {
    // ripple 是旁路訊號，絕不影響主路徑
    console.error("[ingest-ripple] failed:", err);
  }
}

/**
 * 取得目前的 ripple 狀態（供 /dream wikisync 步驟讀取）。
 */
export function getRippleStatus(): RippleStatus {
  const status: RippleStatus = {
    pagesNeedingUpdate: [],
    pagesWatching: [],
  };

